from pico_ioc import component
from pico_celery import task

# 👈 Add @component decorator
class TemplateService:
    def render(self, template_name: str, **kwargs) -> str:
        return f"Rendered {template_name} with {kwargs}"

@component
class EmailTasks:
    def __init__(self, template_service: TemplateService):
        self.template_service = template_service

    @task(name="email.send_welcome")
    async def send_welcome(self, user_email: str) -> str:
        body = self.template_service.render("welcome", email=user_email)
        return f"Sent to {user_email}: {body}"

